def verify(answer):
    # The binary representation of 3/16 should be 0.0011 in base 2
    # Accept answers like '0.0011', '0.00110', etc. (trailing zeros allowed)
    # Accept optional 'b' or 'B' prefix, e.g., '0b0.0011'
    def parse_binary_fraction(s):
        s = s.strip().lower()
        if s.startswith('0b'):
            s = s[2:]
        if '.' not in s:
            return None
        int_part, frac_part = s.split('.', 1)
        if not all(c in '01' for c in int_part+frac_part):
            return None
        # Convert integer part
        int_val = int(int_part, 2) if int_part else 0
        # Convert fractional part
        frac_val = 0
        for i, digit in enumerate(frac_part, 1):
            if digit not in '01':
                return None
            frac_val += int(digit) * (1 / (2 ** i))
        return int_val + frac_val

    try:
        val = parse_binary_fraction(str(answer))
        if val is None:
            return False
        # 3/16 = 0.1875
        return abs(val - 0.1875) < 1e-9
    except Exception:
        return False

